## Overview
Implement context builder to pass all Red phase tests.

## 🟢 Green Phase - Implementation

```typescript
// src/sandbox/context.ts

export interface MethodMetadata {
  description?: string
  params?: string[]
  returns?: string
}

export interface ExecutionContext {
  [key: string]: Function
  __methods__?: Record<string, MethodMetadata>
}

export function buildExecutionContext(instance: {
  allowedMethods: Set<string>
  [key: string]: unknown
}): ExecutionContext {
  const context: ExecutionContext = {}
  const metadata: Record<string, MethodMetadata> = {}

  for (const methodName of instance.allowedMethods) {
    const member = instance[methodName]

    if (typeof member === "function") {
      // Bind method to instance
      context[methodName] = member.bind(instance)

      // Extract metadata if available
      if ("description" in member || "params" in member) {
        metadata[methodName] = {
          description: (member as any).description,
          params: (member as any).params,
          returns: (member as any).returns,
        }
      }
    }
  }

  if (Object.keys(metadata).length > 0) {
    context.__methods__ = metadata
  }

  return context
}
